{% block content %}
<h2>Message History</h2>

<table id="messages-table">
    <thead>
        <tr>
            <th>#</th>
            <th>Candidate</th>
            <th>Template</th>
            <th>Status</th>
            <th>Content</th>
            <th>Sent At</th>
        </tr>
    </thead>
    <tbody id="messages-body">
        <tr><td colspan="6">Loading...</td></tr>
    </tbody>
</table>

<div id="msg-pagination" class="pagination-controls"></div>
