/* Maimai Assistant - Custom Styles */

/* Connection badge */
.badge {
    display: inline-block;
    padding: 0.2em 0.6em;
    font-size: 0.75em;
    font-weight: 600;
    border-radius: 1em;
    background: var(--pico-secondary-background);
    color: var(--pico-secondary);
}

.badge[data-status="ok"],
.badge[data-status="completed"],
.badge[data-status="sent"] {
    background: #d4edda;
    color: #155724;
}

.badge[data-status="warn"],
.badge[data-status="running"],
.badge[data-status="in_progress"],
.badge[data-status="queued"] {
    background: #fff3cd;
    color: #856404;
}

.badge[data-status="error"],
.badge[data-status="failed"],
.badge[data-status="cancelled"] {
    background: #f8d7da;
    color: #721c24;
}

.badge[data-status="awaiting_confirmation"] {
    background: #cce5ff;
    color: #004085;
}

/* Nav spacing */
nav {
    padding-top: 0.5rem;
    padding-bottom: 0.5rem;
}

nav ul li a {
    font-size: 0.9em;
}

/* Article cards */
article {
    margin-bottom: 1rem;
}

article header {
    font-weight: 600;
}

/* Table tweaks */
table {
    font-size: 0.9em;
}

table td, table th {
    padding: 0.5em 0.75em;
}

/* Candidate checkboxes in pipeline confirm */
#candidate-list {
    max-height: 400px;
    overflow-y: auto;
    border: 1px solid var(--pico-muted-border-color);
    border-radius: var(--pico-border-radius);
    padding: 0.5rem;
}

#candidate-list label {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.4rem 0;
    border-bottom: 1px solid var(--pico-muted-border-color);
    margin-bottom: 0;
}

#candidate-list label:last-child {
    border-bottom: none;
}

#candidate-list .candidate-info {
    flex: 1;
    display: flex;
    gap: 1rem;
}

#candidate-list .candidate-name {
    font-weight: 600;
    min-width: 80px;
}

#candidate-list .candidate-title {
    color: var(--pico-muted-color);
    flex: 1;
}

#candidate-list .candidate-company {
    color: var(--pico-primary);
}

/* Pagination controls */
.pagination-controls {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 1rem;
    margin-top: 1rem;
}

.pagination-controls button {
    width: auto;
    margin: 0;
}

/* Progress bar animations */
progress {
    transition: value 0.3s ease;
}

/* Results summary */
#results-summary .stat-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(120px, 1fr));
    gap: 0.5rem;
    margin-top: 0.5rem;
}

#results-summary .stat {
    text-align: center;
    padding: 0.5rem;
    border-radius: var(--pico-border-radius);
    background: var(--pico-card-background-color);
}

#results-summary .stat .value {
    font-size: 1.5em;
    font-weight: 700;
}

#results-summary .stat .label {
    font-size: 0.8em;
    color: var(--pico-muted-color);
}

/* Footer */
footer {
    margin-top: 2rem;
    padding-top: 1rem;
    border-top: 1px solid var(--pico-muted-border-color);
    text-align: center;
    color: var(--pico-muted-color);
}

/**
 * WebSocket client with auto-reconnect for Maimai Assistant.
 */

class MaimaiWS {
    constructor(path, options = {}) {
        this.path = path;
        this.options = options;
        this.ws = null;
        this.reconnectDelay = 1000;
        this.maxReconnectDelay = 30000;
        this.reconnectAttempts = 0;
        this.maxReconnectAttempts = options.maxReconnect || 50;
        this.closed = false;
    }

    connect() {
        if (this.closed) return;

        const protocol = location.protocol === 'https:' ? 'wss:' : 'ws:';
        const url = `${protocol}//${location.host}${this.path}`;

        this.ws = new WebSocket(url);

        this.ws.onopen = () => {
            this.reconnectAttempts = 0;
            this.reconnectDelay = 1000;
            if (this.options.onOpen) this.options.onOpen();
            this._updateStatus('connected');
        };

        this.ws.onmessage = (event) => {
            if (event.data === 'pong') return;

            try {
                const msg = JSON.parse(event.data);
                if (msg.event === 'keepalive') return;
                if (this.options.onMessage) this.options.onMessage(msg);
            } catch (e) {
                console.warn('WS parse error:', e);
            }
        };

        this.ws.onclose = () => {
            this._updateStatus('disconnected');
            if (!this.closed) this._reconnect();
        };

        this.ws.onerror = (err) => {
            console.error('WS error:', err);
        };
    }

    send(data) {
        if (this.ws && this.ws.readyState === WebSocket.OPEN) {
            this.ws.send(typeof data === 'string' ? data : JSON.stringify(data));
        }
    }

    close() {
        this.closed = true;
        if (this.ws) this.ws.close();
    }

    _reconnect() {
        if (this.reconnectAttempts >= this.maxReconnectAttempts) {
            console.warn('WS max reconnect attempts reached');
            return;
        }

        this.reconnectAttempts++;
        const delay = Math.min(
            this.reconnectDelay * Math.pow(1.5, this.reconnectAttempts - 1),
            this.maxReconnectDelay
        );

        setTimeout(() => this.connect(), delay);
    }

    _updateStatus(status) {
        const el = document.getElementById('ws-status');
        if (el) {
            el.textContent = `WebSocket: ${status}`;
        }
    }
}

// Global WebSocket for dashboard updates
let globalWS = null;

function initGlobalWS() {
    globalWS = new MaimaiWS('/ws/global', {
        onMessage(msg) {
            // Global event handler — can be overridden per page
            if (window.onGlobalWSMessage) {
                window.onGlobalWSMessage(msg);
            }
        },
    });
    globalWS.connect();
}

/**
 * Connect a task-specific WebSocket.
 * Returns the MaimaiWS instance. Options:
 *   onEvent(msg)    — called for progress events
 *   onComplete(msg) — called when task completes
 *   onError(msg)    — called when task fails
 */
function connectTaskWS(taskId, options = {}) {
    const ws = new MaimaiWS(`/ws/task/${taskId}`, {
        onMessage(msg) {
            if (msg.event === 'completed') {
                if (options.onComplete) options.onComplete(msg);
                ws.close();
            } else if (msg.event === 'failed') {
                if (options.onError) options.onError(msg);
                ws.close();
            } else {
                if (options.onEvent) options.onEvent(msg);
            }
        },
    });
    ws.connect();
    return ws;
}

// Auto-init global WS when DOM is ready
document.addEventListener('DOMContentLoaded', initGlobalWS);

/**
 * Common utility functions for Maimai Assistant web UI.
 */

function escapeHtml(str) {
    if (!str) return '';
    const div = document.createElement('div');
    div.textContent = str;
    return div.innerHTML;
}

/**
 * Poll a task until it completes (fallback when WebSocket is not available).
 */
async function pollTask(taskId, onUpdate, intervalMs = 2000, maxAttempts = 300) {
    for (let i = 0; i < maxAttempts; i++) {
        try {
            const res = await fetch(`/api/task/${taskId}`);
            const data = await res.json();
            if (onUpdate) onUpdate(data);

            if (data.status === 'completed' || data.status === 'failed' || data.status === 'cancelled') {
                return data;
            }
        } catch (e) {
            console.error('Poll error:', e);
        }
        await new Promise(r => setTimeout(r, intervalMs));
    }
    return null;
}

/**
 * Format a date string for display.
 */
function formatDate(isoStr) {
    if (!isoStr) return '--';
    return new Date(isoStr).toLocaleString();
}

/**
 * Pipeline page interaction logic.
 * Handles form submission, progress tracking, candidate confirmation, and results display.
 */

let pipelineTaskId = null;
let pipelineWS = null;
let pipelineCandidates = [];

document.getElementById('pipeline-form').addEventListener('submit', async (e) => {
    e.preventDefault();
    const form = e.target;

    const keywords = form.keywords.value.split('\n').map(s => s.trim()).filter(Boolean);
    const company = form.company.value.split('\n').map(s => s.trim()).filter(Boolean);
    const template = form.template.value;
    const pages = parseInt(form.pages.value) || 1;
    const auto_send = form.auto_send.checked;
    const dry_run = form.dry_run.checked;

    if (!keywords.length) return alert('Please enter at least one keyword');
    if (!template) return alert('Please select a template');

    // Collect template variables
    const variables = {};
    form.querySelectorAll('[name^="var_"]').forEach(input => {
        const key = input.name.replace('var_', '');
        if (input.value.trim()) variables[key] = input.value.trim();
    });

    // Show progress, hide other sections
    document.getElementById('pipeline-progress').hidden = false;
    document.getElementById('pipeline-confirm').hidden = true;
    document.getElementById('pipeline-results').hidden = true;
    form.querySelector('button').disabled = true;

    try {
        const res = await fetch('/api/pipeline', {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({keywords, company, template, pages, variables, auto_send, dry_run}),
        });
        const data = await res.json();
        pipelineTaskId = data.task_id;
        document.getElementById('pipeline-task-id').textContent = data.task_id;

        // Connect WebSocket for this task
        pipelineWS = connectTaskWS(data.task_id, {
            onEvent(msg) {
                handlePipelineEvent(msg);
            },
            onComplete(msg) {
                showPipelineResults(msg.result);
                document.getElementById('pipeline-progress').hidden = true;
                form.querySelector('button').disabled = false;
            },
            onError(msg) {
                document.getElementById('pipeline-status-text').textContent = 'Failed';
                document.getElementById('pipeline-detail').textContent = msg.error || 'Unknown error';
                form.querySelector('button').disabled = false;
            },
        });

        // Also start polling as fallback
        pollTask(data.task_id, (task) => {
            if (task.status === 'completed') {
                showPipelineResults(task.result);
                document.getElementById('pipeline-progress').hidden = true;
                form.querySelector('button').disabled = false;
                if (pipelineWS) pipelineWS.close();
            }
        }, 3000);

    } catch (e) {
        alert('Request failed: ' + e.message);
        form.querySelector('button').disabled = false;
        document.getElementById('pipeline-progress').hidden = true;
    }
});

function handlePipelineEvent(msg) {
    const statusEl = document.getElementById('pipeline-status-text');
    const detailEl = document.getElementById('pipeline-detail');
    const progressBar = document.getElementById('pipeline-progress-bar');

    switch (msg.event) {
        case 'search_progress':
            statusEl.textContent = `Searching: ${msg.keyword} (${msg.keyword_index}/${msg.total_keywords})`;
            break;

        case 'search_keyword_done':
            detailEl.textContent = `Found ${msg.found} candidates for "${msg.keyword}" (${msg.total_so_far} total)`;
            break;

        case 'search_complete':
            statusEl.textContent = 'Search complete';
            detailEl.textContent = `${msg.candidates.length} candidates found`;
            break;

        case 'awaiting_confirmation':
            statusEl.textContent = 'Awaiting your confirmation';
            document.getElementById('pipeline-progress').hidden = true;
            showConfirmation(msg.candidates);
            break;

        case 'sending_started':
            statusEl.textContent = 'Sending messages...';
            progressBar.max = msg.total;
            progressBar.value = 0;
            document.getElementById('pipeline-progress').hidden = false;
            document.getElementById('pipeline-confirm').hidden = true;
            break;

        case 'send_progress':
            statusEl.textContent = `Sending: ${msg.current} (${msg.sent}/${msg.total})`;
            progressBar.value = msg.sent + msg.failed;
            progressBar.max = msg.total;
            detailEl.textContent = `Sent: ${msg.sent}, Failed: ${msg.failed}`;
            break;

        case 'completed':
            showPipelineResults(msg.result);
            break;

        default:
            detailEl.textContent = JSON.stringify(msg);
    }
}

function showConfirmation(candidates) {
    pipelineCandidates = candidates;
    document.getElementById('pipeline-confirm').hidden = false;
    document.getElementById('confirm-count').textContent = candidates.length;

    const list = document.getElementById('candidate-list');
    list.innerHTML = candidates.map(c => `
        <label>
            <input type="checkbox" value="${c.maimai_id}" checked>
            <span class="candidate-info">
                <span class="candidate-name">${escapeHtml(c.name)}</span>
                <span class="candidate-title">${escapeHtml(c.title)}</span>
                <span class="candidate-company">${escapeHtml(c.company)}</span>
            </span>
        </label>
    `).join('');
}

function toggleSelectAll(checked) {
    document.querySelectorAll('#candidate-list input[type="checkbox"]').forEach(cb => {
        cb.checked = checked;
    });
}

async function confirmCandidates(cancel = false) {
    if (!pipelineTaskId) return;

    let maimai_ids = [];
    if (!cancel) {
        document.querySelectorAll('#candidate-list input[type="checkbox"]:checked').forEach(cb => {
            maimai_ids.push(cb.value);
        });

        if (!maimai_ids.length) {
            return alert('Please select at least one candidate');
        }
    }

    try {
        await fetch(`/api/pipeline/${pipelineTaskId}/confirm`, {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({maimai_ids}),
        });

        document.getElementById('pipeline-confirm').hidden = true;
        if (!cancel) {
            document.getElementById('pipeline-progress').hidden = false;
            document.getElementById('pipeline-status-text').textContent = 'Sending messages...';
        }
    } catch (e) {
        alert('Confirm failed: ' + e.message);
    }
}

function showPipelineResults(result) {
    document.getElementById('pipeline-progress').hidden = true;
    document.getElementById('pipeline-confirm').hidden = true;
    document.getElementById('pipeline-results').hidden = false;

    const summary = document.getElementById('results-summary');

    if (!result || result.error) {
        summary.innerHTML = `<p>Error: ${result ? result.error : 'Unknown'}</p>`;
        return;
    }

    if (result.dry_run) {
        summary.innerHTML = `
            <p>Dry run complete. Found <strong>${result.total}</strong> candidates.</p>
            <p>No messages were sent.</p>
        `;
        return;
    }

    if (result.message) {
        summary.innerHTML = `<p>${escapeHtml(result.message)}</p>`;
        return;
    }

    summary.innerHTML = `
        <div class="stat-grid">
            <div class="stat">
                <div class="value">${result.total || 0}</div>
                <div class="label">Total</div>
            </div>
            <div class="stat" style="color: #155724">
                <div class="value">${result.sent || 0}</div>
                <div class="label">Sent</div>
            </div>
            <div class="stat" style="color: #721c24">
                <div class="value">${result.failed || 0}</div>
                <div class="label">Failed</div>
            </div>
            <div class="stat" style="color: #856404">
                <div class="value">${result.skipped || 0}</div>
                <div class="label">Skipped</div>
            </div>
            <div class="stat" style="color: #856404">
                <div class="value">${result.rate_limited || 0}</div>
                <div class="label">Rate Limited</div>
            </div>
        </div>
    `;
}
